using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1: EF Core 9 changed the default discriminator property
            // from "Discriminator" to "$type". Existing 500K documents use "Discriminator",
            // and direct SQL queries reference c.Discriminator — keep the old name.
            entity.HasDiscriminator<string>("Discriminator").HasValue("Product");

            // BREAKING CHANGE 2: EF Core 9 no longer synthesizes id as "{Discriminator}|{Key}".
            // It now uses just the key value. Existing documents have id = "Product|123".
            // Preserve the old format so existing data remains accessible.
            entity.Property(p => p.Id)
                  .HasConversion(
                      id => $"Product|{id}",
                      stored => int.Parse(stored.Replace("Product|", "")));
            entity.HasPartitionKey(p => p.Id);
        });

        // BREAKING CHANGE 3: HasIndex throws for the Cosmos provider in EF Core 9.
        // Cosmos manages indexing via its own indexing policy — remove it.
        // (Removed: modelBuilder.Entity<Product>().HasIndex(p => p.Sku);)
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

