class CosmosQuery
{
    // BREAKING CHANGE 4: EF Core 9 Cosmos provider removed synchronous I/O.
    // ToList(), First(), SaveChanges(), etc. now throw InvalidOperationException.
    // All calls must use async equivalents.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator" property name
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

